import { VectorStoreIndex, SimpleDirectoryReader, Settings } from 'llamaindex';
import { OpenAI } from '@llamaindex/openai';
import { VexClient, VexVerificationError } from 'vex-sdk';

// Initialize Vex client
const vex = new VexClient({ apiKey: process.env.VEX_API_KEY! });

// Configure LlamaIndex settings
Settings.llm = new OpenAI({ model: 'gpt-4o', temperature: 0.1 });

async function buildQueryEngine() {
  const reader = new SimpleDirectoryReader();
  const documents = await reader.loadData({ directoryPath: './data' });
  const index = await VectorStoreIndex.fromDocuments(documents);
  return index.asQueryEngine({ similarityTopK: 5 });
}

async function safeQuery(queryEngine: any, queryText: string): Promise<string> {
  const verifier = vex.verify({
    framework: 'llamaindex',
    checks: ['context_relevance', 'response_grounding', 'empty_response'],
    thresholds: {
      minSimilarityScore: 0.65,
      maxHallucinationRate: 0.05,
      minNodesRetrieved: 2
    }
  });

  try {
    const response = await queryEngine.query({ query: queryText });

    // Inspect LlamaIndex response with Vex
    await verifier.inspect({
      response: response.toString(),
      sourceNodes: response.sourceNodes,
      metadata: response.metadata
    });

    return response.toString();
  } catch (error) {
    if (error instanceof VexVerificationError) {
      console.error(`Guardrail triggered: ${error.checkName} — ${error.message}`);
      throw error;
    }
    throw error;
  }
}

// Usage
(async () => {
  const queryEngine = await buildQueryEngine();
  const result = await safeQuery(queryEngine, 'What are the payment terms?');
  console.log(result);
})();
